package com.school.sis.grade.entity;
import com.school.sis.auth.entity.User; import com.school.sis.common.audit.AuditableEntity; import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="gradebook_status_history") public class GradebookStatusHistory extends AuditableEntity {
 @Id private UUID id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="gradebook_id") private ClassGradebook gradebook; @Enumerated(EnumType.STRING) @Column(name="from_status") private GradeStatus fromStatus; @Enumerated(EnumType.STRING) @Column(name="to_status",nullable=false) private GradeStatus toStatus; private String reason; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="changed_by") private User changedBy; @Column(name="changed_at",nullable=false) private Instant changedAt;
 @PrePersist void pre(){if(id==null)id=UUID.randomUUID();if(changedAt==null)changedAt=Instant.now();} public UUID getId(){return id;} public ClassGradebook getGradebook(){return gradebook;} public void setGradebook(ClassGradebook v){gradebook=v;} public GradeStatus getFromStatus(){return fromStatus;} public void setFromStatus(GradeStatus v){fromStatus=v;} public GradeStatus getToStatus(){return toStatus;} public void setToStatus(GradeStatus v){toStatus=v;} public String getReason(){return reason;} public void setReason(String v){reason=v;} public User getChangedBy(){return changedBy;} public void setChangedBy(User v){changedBy=v;} public Instant getChangedAt(){return changedAt;} public void setChangedAt(Instant v){changedAt=v;}
}
